from flask import Flask, request, jsonify
from flask_bcrypt import Bcrypt
from flask_limiter import Limiter
from flask_limiter.util import get_remote_address
import jwt
import datetime

app = Flask(__name__)
bcrypt = Bcrypt(app)
limiter = Limiter(
    app,
    key_func=get_remote_address,
    default_limits=["200 per day", "50 per hour"]
)

# Secret key for token generation
secret_key = 'your_secret_key_here'

# User database (in a real application, use a database like MySQL or MongoDB)
users = {
    'user1': bcrypt.generate_password_hash('password1').decode('utf-8'),
    'user2': bcrypt.generate_password_hash('password2').decode('utf-8')
}

@app.route('/login', methods=['POST'])
@limiter.limit("10 per minute")
def login():
    username = request.json.get('username')
    password = request.json.get('password')

    if username in users and bcrypt.check_password_hash(users[username], password):
        token = jwt.encode({
            'user': username,
            'exp': datetime.datetime.utcnow() + datetime.timedelta(minutes=30)
        }, secret_key, algorithm='HS256').decode('utf-8')
        return jsonify({'token': token})
    else:
        return jsonify({'error': 'Invalid credentials'}), 401

@app.route('/protected', methods=['GET'])
def protected():
    token = request.headers.get('Authorization')

    if not token:
        return jsonify({'error': 'Missing authorization header'}), 401

    try:
        payload = jwt.decode(token, secret_key, algorithms=['HS256'])
        return jsonify({'message': f'Hello {payload["user"]}!'})
    except jwt.ExpiredSignatureError:
        return jsonify({'error': 'Token has expired'}), 401
    except jwt.InvalidTokenError:
        return jsonify({'error': 'Invalid token'}), 401

if __name__ == '__main__':
    app.run(debug=True)